fective from</th><th>Actions</th></tr></thead><tbody><tr v-for="row in filteredStructures" :key="row.fee_structure_id"><td>{{ row.structure_name }}</td><td>{{ row.class_name }}<small>{{ row.year_name }}</small></td><td>{{ row.branch_name }}</td><td>{{ row.items }}</td><td>৳ {{ money(row.total) }}</td><td>{{ date(row.effective_from) }}</td><td><div class="row-actions"><button class="text-button" @click="editStructure(row)">Edit</button><button class="text-button danger" @click="removeStructure(row)">Delete</button></div></td></tr><tr v-if="!filteredStructures.length"><td colspan="7" class="empty">No fee structures match the selected filters.</td></tr></tbody></table></BaseCard></template>

    <template v-else-if="section === 'assignments'"><BaseCard title="Automatic class-wise assignment"><p class="auto-assignment-note">Fee structures are assigned automatically to every active student in the selected branch, academic year, class, and optional group or medium. New students receive the applicable structure as soon as they are enrolled.</p></BaseCard><BaseCard title="Find automatic assignments"><div class="filter-grid"><label>Student or structure<input v-model.trim="assignmentFilters.query" placeholder="Student no., name, or structure" /></label><label>Class<select v-model="assignmentFilters.class_name"><option value="">All classes</option><option v-for="row in lookups.classes" :key="row.class_id" :value="row.class_name">{{ row.class_name_bn || row.class_name }}</option></select></label><label>Status<select v-model="assignmentFilters.status"><option value="">All statuses</option><option>ACTIVE</option><option>INACTIVE</option></select></label><div class="filter-actions"><button type="button" class="text-button" @click="resetFilters(assignmentFilters)">Clear filters</button></div></div></BaseCard><BaseCard title="Student fee assignments"><table><thead><tr><th>Student</th><th>Class / Year</th><th>Structure</th><th>Discount</th><th>Status</th></tr></thead><tbody><tr v-for="row in filteredAssignments" :key="row.assignment_id"><td>{{ row.full_name }}<small>{{ row.student_no }}</small></td><td>{{ row.class_name }}<small>{{ row.year_name }}</small></td><td>{{ row.structure_name }}</td><td>{{ row.discount_percent }}% + ৳ {{ money(row.discount_amount) }}</td><td>{{ row.status }}</td></tr><tr v-if="!filteredAssignments.length"><td colspan="5" class="empty">No automatic assignments match the selected filters.</td></tr></tbody></table></BaseCard></template>

    <template v-else-if="section === 'invoices'"><BaseCard title="Generate invoices for a class"><form class="form-grid" @submit.prevent="generateBulkInvoices"><label>Branch<select v-model="bulkInvoiceForm.branch_id" required><option value="">Select branch</option><option v-for="row in lookups.branches" :key="row.branch_id" :value="row.branch_id">{{ row.branch_name }}</option></select></label><label>Academic year<select v-model="bulkInvoiceForm.academic_year_id" required><option value="">Select year</option><option v-for="row in lookups.years" :key="row.academic_year_id" :value="row.academic_year_id">{{ row.year_name }}</option></select></label><label>Class<select v-model="bulkInvoiceForm.class_id" required><option value="">Select class</option><option v-for="row in lookups.classes" :key="row.class_id" :value="row.class_id">{{ row.class_name_bn || row.class_name }}</option></select></label><label>Group (optional)<select v-model="bulkInvoiceForm.group_id"><option value="">All groups</option><option v-for="row in lookups.groups" :key="row.group_id" :value="row.group_id">{{ row.group_name }}</option></select></label><label>Medium (optional)<select v-model="bulkInvoiceForm.medium_id"><option value="">All mediums</option><option v-for="row in lookups.mediums" :key="row.medium_id" :value="row.medium_id">{{ row.medium_name }}</option></select></label><label>Billing month<input v-model.number="bulkInvoiceForm.billing_month" type="number" min="1" max="12" required /></label><label>Billing year<input v-model.number="bulkInvoiceForm.billing_year" type="number" min="2020" max="2100" required /></label><label>Due date<input v-model="bulkInvoiceForm.due_date" type="date" /></label><label class="wide">Remarks<input v-model.trim="bulkInvoiceForm.remarks" placeholder="Optional note for every invoice" /></label><div class="actions"><BaseButton type="submit">Generate Class Invoices</BaseButton></div></form></BaseCard><BaseCard title="Generate one student invoice (when needed)"><form class="form-grid" @submit.prevent="generateInvoice"><label>Fee assignment<select v-model="invoiceForm.assignment_id" required><option value="">Select assignment</option><option v-for="row in assignments" :key="row.assignment_id" :value="row.assignment_id">{{ row.student_no }} — {{ row.full_name }} — {{ row.structure_name }}</option></select></label><label>Billing month<input v-model.number="invoiceForm.billing_month" type="number" min="1" max="12" /></label><label>Billing year<input v-model.number="invoiceForm.billing_year" type="number" min="2020" max="2100" /></label><label>Due date<input v-model="invoiceForm.due_date" type="date" /></label><label class="wide">Remarks<input v-model.trim="invoiceForm.remarks" placeholder="Optional invoice note" /></label><div class="actions"><BaseButton type="submit">Generate Single Invoice</BaseButton></div></form></BaseCard><BaseCard title="Fee invoices"><template #header-action><div class="invoice-header-filters"><label>Student / Invoice / Student ID<input v-model.trim="invoiceFilters.query" placeholder="Search student or invoice" /></label><label>Status<select v-model="invoiceFilters.status"><option value="">All statuses</option><option>UNPAID</option><option>PARTIAL</option><option>PAID</option><option>CANCELLED</option></select></label></div></template><table><thead><tr><th>Invoice</th><th>Student</th><th>Issued</th><th>Net</th><th>Paid</th><th>Due</th><th>Status</th><th>Actions</th></tr></thead><tbody><tr v-for="row in filteredInvoices" :key="row.invoice_id"><td>{{ row.invoice_no }}<small>Due: {{ date(row.due_date) }}</small></td><td>{{ row.full_name }}<small>{{ row.student_no }}</small></td><td>{{ date(row.invoice_date) }}</td><td>৳ {{ money(row.net_amount) }}</td><td>৳ {{ money(row.paid_amount) }}</td><td>৳ {{ money(row.due_amount) }}</td><td><span class="pill" :class="row.invoice_status.toLowerCase()">{{ row.invoice_status }}</span></td><td><div class="row-actions"><button class="text-button" @click="editInvoice(row)">Edit</button><button v-if="Number(row.paid_amount) === 0" class="text-button" @click="regenerateInvoice(row)">Regenerate</button><button v-if="Number(row.paid_amount) === 0" class="text-button danger" @click="removeInvoice(row)">Delete</button></div></td></tr><tr v-if="!filteredInvoices.length"><td colspan="8" class="empty">No invoices match the selected filters.</td></tr></tbody></table></BaseCard></template>

    <template v-else-if="section === 'collections'"><BaseCard title="Collect fee payment"><form class="form-grid" @submit.prevent="saveCollection"><label>Invoice<select v-model="collectionForm.invoice_id" required @change="selectInvoice"><option value="">Select unpaid invoice</option><option v-for="row in payableInvoices" :key="row.invoice_id" :value="row.invoice_id">{{ row.invoice_no }} — {{ row.full_name }} (Due ৳ {{ money(row.due_amount) }})</option></select></label><label>Payment amount<input v-model.number="collectionForm.paid_amount" type="number" min="0.01" step="0.01" required /></label><label>Payment method<select v-model="collectionForm.payment_method"><option v-for="method in paymentMethods" :key="method">{{ method }}</option></select></label><label>Collection date<input v-model="collectionForm.collection_date" type="date" required /></label><label>Reference no.<input v-model.trim="collectionForm.reference_no" placeholder="Transaction / cheque no." /></label><label>Fine<input v-model.number="collectionForm.fine_amount" type="number" min="0" step="0.01" /></label><label>Discount<input v-model.number="collectionForm.discount_amount" type="number" min="0" step="0.01" /></label><div class="actions"><BaseButton type="submit">Save Collection</BaseButton></div></form></BaseCard><BaseCard title="Find fee collections"><div class="filter-grid"><label>Student or receipt<input v-model.trim="collectionFilters.query" placeholder="Student no., name, or receipt" /></label><label>Payment method<select v-model="collectionFilters.payment_method"><option value="">All methods</option><option v-for="method in paymentMethods" :key="method">{{ method }}</option></select></label><label>Collected from<input v-model="collectionFilters.from" type="date" /></label><label>Collected to<input v-model="collectionFilters.to" type="date" /></label><div class="filter-actions"><button type="button" class="text-button" @click="resetFilters(collectionFilters)">Clear filters</button></div></div></BaseCard><BaseCard title="Collection history"><table><thead><tr><th>Receipt</th><th>Student</th><th>Date</th><th>Method</th><th>Amount</th><th>Actions</th></tr></thead><tbody><tr v-for="row in filteredCollections" :key="row.collection_id"><td>{{ row.receipt_no }}</td><td>{{ row.full_name }}<small>{{ row.student_no }}</small></td><td>{{ date(row.collection_date) }}</td><td>{{ row.payment_method }}</td><td>৳ {{ money(row.total_amount) }}</td><td><div class="row-actions"><button class="text-button" @click="editCollection(row)">Edit</button><button class="text-button danger" @click="removeCollection(row)">Delete</button></div></td></tr><tr v-if="!filteredCollections.length"><td colspan="6" class="empty">No fee collections match the selected filters.</td></tr></tbody></table></BaseCard></template>

    <template v-else-if="section === 'waivers'"><BaseCard :title="editingWaiver ? 'Edit fee waiver' : 'Create fee waiver'"><form class="form-grid" @submit.prevent="saveWaiver"><label>Student<select v-model="waiverForm.student_id" required><option value="">Select student</option><option v-for="row in uniqueStudents" :key="row.student_id" :value="row.student_id">{{ row.student_no }} — {{ row.full_name }}</option></select></label><label>Fee head (optional)<select v-model="waiverForm.fee_head_id"><option value="">All applicable heads</option><option v-for="row in lookups.heads" :key="row.fee_head_id" :value="row.fee_head_id">{{ row.fee_name }}</option></select></label><label>Waiver type<select v-model="waiverForm.waiver_type"><option>PERCENT</option><option>FIXED</option></select></label><label>Value<input v-model.number="waiverForm.waiver_value" required min="0.01" step="0.01" type="number" /></label><label>Effective from<input v-model="waiverForm.effective_from" required type="date" /></label><label>Effective to<input v-model="waiverForm.effective_to" type="date" /></label><label class="wide">Remarks<input v-model.trim="waiverForm.remarks" /></label><div class="actions"><BaseButton type="button" variant="secondary" @click="resetWaiver">Clear</BaseButton><BaseButton type="submit">{{ editingWaiver ? 'Update Waiver' : 'Save Waiver' }}</BaseButton></div></form></BaseCard><BaseCard title="Find fee waivers"><div class="filter-grid"><label>Text search<input v-model.trim="waiverFilters.query" placeholder="Student no., name, or fee head" /></label><label>Status<select v-model="waiverFilters.status"><option value="">All statuses</option><option>PENDING</option><option>APPROVED</option><option>REJECTED</option></select></label><div class="filter-actions"><button type="button" class="text-button" @click="resetFilters(waiverFilters)">Clear filters</button></div></div></BaseCard><BaseCard title="Fee waivers"><table><thead><tr><th>Student</th><th>Fee head</th><th>Waiver</th><th>Period</th><th>Status</th><th>Actions</th></tr></thead><tbody><tr v-for="row in filteredWaivers" :key="row.waiver_id"><td>{{ row.full_name }}<small>{{ row.student_no }}</small></td><td>{{ row.fee_name || 'All fees' }}</td><td>{{ row.waiver_value }} {{ row.waiver_type === 'PERCENT' ? '%' : '৳' }}</td><td>{{ date(row.effective_from) }}<small>{{ row.effective_to ? `to ${date(row.effective_to)}` : 'Open ended' }}</small></td><td><span class="pill" :class="row.approval_status.toLowerCase()">{{ row.approval_status }}</span></td><td><div class="row-actions"><button v-if="row.approval_status === 'PENDING'" class="text-button" @click="approveWaiver(row)">Approve</button><button class="text-button" @click="editWaiver(row)">Edit</button><button class="text-button danger" @click="removeWaiver(row)">Delete</button></div></td></tr><tr v-if="!filteredWaivers.length"><td colspan="6" class="empty">No fee waivers match the selected filters.</td></tr></tbody></table></BaseCard></template>
  </section>
</template>

<script setup>
import { computed, onMounted, reactive, ref, watch } from "vue";
import { useRoute, RouterLink } from "vue-router";
import BaseButton from "../../components/common/BaseButton.vue";
import BaseCard from "../../components/common/BaseCard.vue";
import { feeApi } from "../../services/api";
const route = useRoute(); const heads = ref([]), structures = ref([]), assignments = ref([]), invoices = ref([]), collections = ref([]), waivers = ref([]), dashboard = reactive({ summary: {}, dueInvoices: [], recentCollections: [] }), lookups = reactive({ heads: [], branches: [], years: [], classes: [], groups: [], mediums: [], students: [] }); const message = ref(""), messageType = ref("success"), editingHead = ref(null);
const feeTypes = ["REGULAR", "ADMISSION", "TUITION", "EXAM", "TRANSPORT", "OTHER"], frequencies = ["ONE_TIME", "MONTHLY", "QUARTERLY", "YEARLY"], paymentMethods = ["CASH", "BANK", "BKASH", "NAGAD", "CARD"];
const section = computed(() => route.meta.feeSection || "dashboard"); const labels = { dashboard: ["Fee Dashboard", "Billing, collection and outstanding amount overview."], reports: ["Fee Reports", "Outstanding invoices and recent collection report."], heads: ["Fee Heads", "Set up every fee type collected by the institution."], structures: ["Fee Structures", "Define class-wise fees once; they are applied automatically."], assignments: ["Automatic Fee Assignment", "Class-wise fee structures are applied to students automatically."], invoices: ["Fee Invoices", "Generate payable invoices from student fee assignments."], collections: ["Fee Collection", "Receive cash, bank, bKash, Nagad or card payments."], waivers: ["Fee Waivers", "Record and approve scholarship or special waivers."] }; const sectionTitle = computed(() => labels[section.value][0]), sectionDescription = computed(() => labels[section.value][1]);
const headForm = reactive({ fee_code: "", fee_name: "", fee_type: "REGULAR", is_recurring: false, status: "ACTIVE" }); const structureForm = reactive({ branch_id: "", academic_year_id: "", class_id: "", group_id: "", medium_id: "", structure_name: "", effective_from: new Date().toISOString().slice(0,10), effective_to: "", details: [{ fee_head_id: "", amount: 0, frequency: "ONE_TIME", due_day: "" }] }); const bulkInvoiceForm = reactive({ branch_id: "", academic_year_id: "", class_id: "", group_id: "", medium_id: "", billing_month: new Date().getMonth() + 1, billing_year: new Date().getFullYear(), due_date: "", remarks: "" }); const invoiceForm = reactive({ assignment_id: "", billing_month: new Date().getMonth() + 1, billing_year: new Date().getFullYear(), due_date: "", remarks: "" }); const collectionForm = reactive({ invoice_id: "", student_id: "", branch_id: "", paid_amount: 0, payment_method: "CASH", collection_date: new Date().toISOString().slice(0,10), reference_no: "", fine_amount: 0, discount_amount: 0 }); const waiverForm = reactive({ student_id: "", fee_head_id: "", waiver_type: "PERCENT", waiver_value: 0, effective_from: new Date().toISOString().slice(0,10), effective_to: "", remarks: "" });
const headFilters = reactive({ query: "", status: "" }); const structureFilters = reactive({ query: "", branch_id: "", academic_year_id: "", class_id: "" }); const assignmentFilters = reactive({ query: "", class_name: "", status: "" }); const invoiceFilters = reactive({ query: "", status: "" }); const collectionFilters = reactive({ query: "", payment_method: "", from: "", to: "" }); const waiverFilters = reactive({ query: "", status: "" });
const editingStructure = computed(() => Boolean(structureForm.fee_structure_id));
const editingWaiver = computed(() => Boolean(waiverForm.waiver_id));
const money = (value) => Number(value || 0).toLocaleString("en-BD", { minimumFractionDigits: 2, maximumFractionDigits: 2 }); const date = (value) => value ? new Intl.DateTimeFormat("en-GB", { day: "2-digit", month: "short", year: "numeric" }).format(new Date(String(value).includes("T") ? value : `${value}T00:00:00`)).toUpperCase() : "—"; const includes = (value, query) => !query || String(value || "").toLowerCase().includes(query.toLowerCase()); const same = (value, filter) => !filter || String(value) === String(filter); const dateValue = (value) => String(value || "").slice(0, 10); const inDateRange = (value, from, to) => { const current = dateValue(value); return (!from || current >= from) && (!to || current <= to); }; const resetFilters = (filters) => Object.keys(filters).forEach(key => { filters[key] = ""; }); const uniqueStudents = computed(() => [...new Map(lookups.students.map(row => [row.student_id, row])).values()]); const payableInvoices = computed(() => invoices.value.filter(row => Number(row.due_amount) > 0 && row.invoice_status !== "CANCELLED"));
const filteredHeads = computed(() => heads.value.filter(row => (includes(row.fee_code, headFilters.query) || includes(row.fee_name, headFilters.query)) && same(row.status, headFilters.status)));
const filteredStructures = computed(() => structures.value.filter(row => includes(row.structure_name, structureFilters.query) && same(row.branch_id, structureFilters.branch_id) && same(row.academic_year_id, structureFilters.academic_year_id) && same(row.class_id, structureFilters.class_id)));
const filteredAssignments = computed(() => assignments.value.filter(row => (includes(row.student_no, assignmentFilters.query) || includes(row.full_name, assignmentFilters.query) || includes(row.structure_name, assignmentFilters.query)) && same(row.class_name, assignmentFilters.class_name) && same(row.status, assignmentFilters.status)));
const filteredInvoices = computed(() => invoices.value.filter(row => (includes(row.invoice_no, invoiceFilters.query) || includes(row.student_no, invoiceFilters.query) || includes(row.full_name, invoiceFilters.query)) && same(row.invoice_status, invoiceFilters.status)));
const filteredCollections = computed(() => collections.value.filter(row => (includes(row.receipt_no, collectionFilters.query) || includes(row.student_no, collectionFilters.query) || includes(row.full_name, collectionFilters.query)) && same(row.payment_method, collectionFilters.payment_method) && inDateRange(row.collection_date, collectionFilters.from, collectionFilters.to)));
const filteredWaivers = computed(() => waivers.value.filter(row => (includes(row.student_no, waiverFilters.query) || includes(row.full_name, waiverFilters.query) || includes(row.fee_name, waiverFilters.query)) && same(row.approval_status, waiverFilters.status)));
function show(text, type = "success") { message.value = text; messageType.value = type; } async function loadLookups() { Object.assign(lookups, (await feeApi.lookups()).data.data); } async function load() { try { if (!lookups.students.length) await loadLookups(); if (["dashboard", "reports"].includes(section.value)) Object.assign(dashboard, (await feeApi.dashboard()).data.data); if (section.value === "heads") heads.value = (await feeApi.heads()).data.data; if (["structures", "assignments"].includes(section.value)) structures.value = (await feeApi.structures()).data.data; if (["assignments", "invoices"].includes(section.value)) assignments.value = (await feeApi.assignments()).data.data; if (["invoices", "collections"].includes(section.value)) invoices.value = (await feeApi.invoices()).data.data; if (section.value === "collections") collections.value = (await feeApi.collections()).data.data; if (section.value === "waivers") waivers.value = (await feeApi.waivers()).data.data; } catch (error) { show(error.response?.data?.message || "Could not load fee data.", "error"); } }
function resetHead() { editingHead.value = null; Object.assign(headForm, { fee_code: "", fee_name: "", fee_type: "REGULAR", is_recurring: false, status: "ACTIVE" }); } function editHead(head) { editingHead.value = head.fee_head_id; Object.assign(headForm, { ...head, is_recurring: Boolean(Number(head.is_recurring)) }); } async function saveHead() { try { editingHead.value ? await feeApi.updateHead(editingHead.value, headForm) : await feeApi.createHead(headForm); show("Fee head saved."); resetHead(); await loadLookups(); await load(); } catch (error) { show(error.response?.data?.message || "Could not save fee head.", "error"); } } function addDetail() { structureForm.details.push({ fee_head_id: "", amount: 0, frequency: "ONE_TIME", due_day: "" }); } async function saveStructure() { try { const response = await feeApi.createStructure(structureForm); const count = response.data.data.auto_assigned_students || 0; show(`Fee structure saved and automatically assigned to ${count} student${count === 1 ? "" : "s"}.`); Object.assign(structureForm, { branch_id: "", academic_year_id: "", class_id: "", group_id: "", medium_id: "", structure_name: "", effective_from: new Date().toISOString().slice(0,10), effective_to: "", details: [{ fee_head_id: "", amount: 0, frequency: "ONE_TIME", due_day: "" }] }); await load(); } catch (error) { show(error.response?.data?.message || "Could not save fee structure.", "error"); } } async function generateInvoice() { try { const response = await feeApi.generateInvoice(invoiceForm); show(`Invoice ${response.data.data.invoice_no} generated.`); await load(); } catch (error) { show(error.response?.data?.message || "Could not generate invoice.", "error"); } } function selectInvoice() { const item = invoices.value.find(row => String(row.invoice_id) === String(collectionForm.invoice_id)); Object.assign(collectionForm, { student_id: item?.student_id || "", branch_id: item?.branch_id || "", paid_amount: Number(item?.due_amount || 0) }); } async function saveCollection() { try { const response = await feeApi.createCollection({ ...collectionForm, lines: [{ invoice_id: collectionForm.invoice_id, paid_amount: collectionForm.paid_amount, fine_amount: collectionForm.fine_amount, discount_amount: collectionForm.discount_amount }] }); show(response.data.message || "Collection saved."); Object.assign(collectionForm, { invoice_id: "", student_id: "", branch_id: "", paid_amount: 0, payment_method: "CASH", collection_date: new Date().toISOString().slice(0,10), reference_no: "", fine_amount: 0, discount_amount: 0 }); await load(); } catch (error) { show(error.response?.data?.message || "Could not save collection.", "error"); } } async function saveWaiver() { try { await feeApi.createWaiver(waiverForm); show("Fee waiver created for approval."); await load(); } catch (error) { show(error.response?.data?.message || "Could not create waiver.", "error"); } } async function approveWaiver(row) { try { await feeApi.approveWaiver(row.waiver_id); show("Fee waiver approved."); await load(); } catch (error) { show(error.response?.data?.message || "Could not approve waiver.", "error"); } }
function resetStructure() { delete structureForm.fee_structure_id; Object.assign(structureForm, { branch_id: "", academic_year_id: "", class_id: "", group_id: "", medium_id: "", structure_name: "", effective_from: new Date().toISOString().slice(0,10), effective_to: "", details: [{ fee_head_id: "", amount: 0, frequency: "ONE_TIME", due_day: "" }] }); }
async function editStructure(row) { try { const response = await feeApi.structure(row.fee_structure_id), structure = response.data.data; Object.assign(structureForm, { fee_structure_id: structure.fee_structure_id, branch_id: structure.branch_id, academic_year_id: structure.academic_year_id, class_id: structure.class_id, group_id: structure.group_id || "", medium_id: structure.medium_id || "", structure_name: structure.structure_name, effective_from: dateValue(structure.effective_from), effective_to: dateValue(structure.effective_to), details: structure.details.map(item => ({ fee_head_id: item.fee_head_id, amount: Number(item.amount), frequency: item.frequency, due_day: item.due_day || "" })) }); } catch (error) { show(error.response?.data?.message || "Could not load fee structure.", "error"); } }
async function removeStructure(row) { if (!window.confirm(`Delete fee structure “${row.structure_name}”? Existing invoices will remain unchanged.`)) return; try { await feeApi.deleteStructure(row.fee_structure_id); if (Number(structureForm.fee_structure_id) === Number(row.fee_structure_id)) resetStructure(); show("Fee structure deleted."); await load(); } catch (error) { show(error.response?.data?.message || "Could not delete fee structure.", "error"); } }
function resetWaiver() { delete waiverForm.waiver_id; Object.assign(waiverForm, { student_id: "", fee_head_id: "", waiver_type: "PERCENT", waiver_value: 0, effective_from: new Date().toISOString().slice(0,10), effective_to: "", remarks: "" }); }
function editWaiver(row) { Object.assign(waiverForm, { waiver_id: row.waiver_id, student_id: row.student_id, fee_head_id: row.fee_head_id || "", waiver_type: row.waiver_type, waiver_value: Number(row.waiver_value), effective_from: dateValue(row.effective_from), effective_to: dateValue(row.effective_to), remarks: row.remarks || "" }); }
async function removeWaiver(row) { if (!window.confirm(`Delete this waiver for ${row.full_name}?`)) return; try { await feeApi.deleteWaiver(row.waiver_id); if (Number(waiverForm.waiver_id) === Number(row.waiver_id)) resetWaiver(); show("Fee waiver deleted."); await load(); } catch (error) { show(error.response?.data?.message || "Could not delete fee waiver.", "error"); } }
async function editInvoice(row) { const due_date = window.prompt("Due date (YYYY-MM-DD, leave blank to clear)", dateValue(row.due_date)); if (due_date === null) return; const remarks = window.prompt("Invoice remarks", row.remarks || ""); if (remarks === null) return; try { await feeApi.updateInvoice(row.invoice_id, { due_date, remarks }); show("Invoice updated."); await load(); } catch (error) { show(error.response?.data?.message || "Could not update invoice.", "error"); } }
async function regenerateInvoice(row) { if (!window.confirm(`Regenerate ${row.invoice_no}? Current unpaid invoice lines will be replaced.`)) return; try { await feeApi.regenerateInvoice(row.invoice_id, { due_date: row.due_date, remarks: row.remarks }); show("Invoice regenerated from the current class-wise fee structure."); await load(); } catch (error) { show(error.response?.data?.message || "Could not regenerate invoice.", "error"); } }
async function removeInvoice(row) { if (!window.confirm(`Delete unpaid invoice ${row.invoice_no}?`)) return; try { await feeApi.deleteInvoice(row.invoice_id); show("Invoice deleted."); await load(); } catch (error) { show(error.response?.data?.message || "Could not delete invoice.", "error"); } }
async function editCollection(row) { const collection_date = window.prompt("Collection date (YYYY-MM-DD)", dateValue(row.collection_date)); if (collection_date === null) return; const payment_method = window.prompt("Payment method (CASH, BANK, BKASH, NAGAD, CARD)", row.payment_method); if (payment_method === null) return; const reference_no = window.prompt("Reference number", row.reference_no || ""); if (reference_no === null) return; const remarks = window.prompt("Remarks", row.remarks || ""); if (remarks === null) return; try { await feeApi.updateCollection(row.collection_id, { collection_date, payment_method, reference_no, remarks }); show("Collection updated."); await load(); } catch (error) { show(error.response?.data?.message || "Could not update collection.", "error"); } }
async function removeCollection(row) { if (!window.confirm(`Delete receipt ${row.receipt_no}? Its payment will be removed from the related invoice.`)) return; try { await feeApi.deleteCollection(row.collection_id); show("Collection deleted and invoice balances restored."); await load(); } catch (error) { show(error.response?.data?.message || "Could not delete collection.", "error"); } }
async function generateBulkInvoices() { try { const response = await feeApi.generateBulkInvoices(bulkInvoiceForm); const { generated = 0, skipped = 0 } = response.data.data || {}; show(`${generated} class invoice${generated === 1 ? "" : "s"} generated${skipped ? `; ${skipped} already existed and were skipped` : ""}.`); await load(); } catch (error) { show(error.response?.data?.message || "Could not generate class invoices.", "error"); } }
watch(section, load); onMounted(load);
</script>

