 1fr 1fr auto;gap:8px;margin-top:8px}.remove,.text-button{border:0;background:transparent;color:#2563eb;font-weight:800;cursor:pointer}.row-actions{display:flex;flex-wrap:wrap;gap:7px}.row-actions .danger{color:#dc2626}.remove{font-size:20px;color:#dc2626}.message{padding:12px;border-radius:10px;font-weight:700}.message.success{background:#dcfce7;color:#166534}.message.error{background:#fee2e2;color:#b91c1c}.auto-assignment-note{margin:0;color:#334155;line-height:1.6}table{width:100%;border-collapse:collapse}th,td{padding:11px;text-align:left;border-bottom:1px solid #e2e8f0;font-size:13px;vertical-align:top}th{color:#64748b;font-size:11px;text-transform:uppercase}.empty{text-align:center;color:#64748b;padding:24px}.pill{display:inline-block;padding:4px 8px;border-radius:999px;background:#e0f2fe;color:#075985;font-size:11px;font-weight:900}.pill.paid,.pill.approved,.pill.active{background:#dcfce7;color:#166534}.pill.unpaid,.pill.pending{background:#fef3c7;color:#92400e}.pill.cancelled,.pill.inactive{background:#fee2e2;color:#b91c1c}@media(max-width:900px){.stats,.two-col,.form-grid,.filter-grid,.invoice-header-filters{grid-template-columns:1fr}.invoice-header-filters{min-width:0;width:100%}.page-header{align-items:flex-start;flex-direction:column}.fee-line{grid-template-columns:1fr 1fr}.fees-page{overflow:auto}}</style>
